async (params, browser) => {
  // Open playlist page
  await browser.open(`${params.playlist_url}`)

  // Wait for playlist videos to load
  await browser.waitForSelector('ytd-playlist-video-renderer', 15000)

  // Let playlist render
  await browser.wait(2000)

  // Scroll to load more playlist items
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(2000)

  // Continue scrolling for more items
  await browser.scroll({ direction: 'down', amount: 1500 })

  await browser.wait(1500)

  // Extract playlist contents
  const playlist_data = await browser.evaluate(`const titleEl = document.querySelector('yt-formatted-string.ytd-playlist-header-renderer, h1#title yt-formatted-string, .metadata-wrapper yt-formatted-string'); const channelEl = document.querySelector('#owner-text a, ytd-playlist-header-renderer #owner-text a'); const statsEls = document.querySelectorAll('.metadata-stats yt-formatted-string, .byline-item-container .byline-item'); const videoCountText = statsEls[0] ? statsEls[0].textContent.trim() : ''; const viewsText = statsEls[1] ? statsEls[1].textContent.trim() : ''; const descEl = document.querySelector('#description-text, .playlist-description yt-formatted-string'); const videos = []; const videoRenderers = document.querySelectorAll('ytd-playlist-video-renderer'); for (let i = 0; i < Math.min(videoRenderers.length, 50); i++) { const el = videoRenderers[i]; const vidTitleEl = el.querySelector('#video-title'); const vidChannelEl = el.querySelector('#channel-name #text a, #byline a'); const durationEl = el.querySelector('badge-shape .badge-shape-wiz__text, ytd-thumbnail-overlay-time-status-renderer span'); const indexEl = el.querySelector('#index'); const linkEl = el.querySelector('a#video-title'); const href = linkEl ? linkEl.getAttribute('href') : ''; videos.push({ index: indexEl ? indexEl.textContent.trim() : String(i + 1), title: vidTitleEl ? vidTitleEl.textContent.trim() : 'Unknown', channel: vidChannelEl ? vidChannelEl.textContent.trim() : '', duration: durationEl ? durationEl.textContent.trim() : '', url: href ? 'https://www.youtube.com' + href : '' }); } return { playlist_title: titleEl ? titleEl.textContent.trim() : 'Unknown', playlist_channel: channelEl ? channelEl.textContent.trim() : '', video_count: videoCountText, total_views: viewsText, description: descEl ? descEl.textContent.trim().substring(0, 500) : '', scraped_count: videos.length, videos: videos }`)

  return playlist_data
}
